  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './search_dropdown.scss';
 10→
 11→export interface SearchDropdownOption {
 12→  label: string;
 13→  value: string;
 14→  icon?: ReactNode;
 15→}
 16→
 17→export interface SearchDropdownSection {
 18→  title?: string;
 19→  options: SearchDropdownOption[];
 20→}
 21→
 22→interface SearchDropdownProps {
 23→  sections: SearchDropdownSection[];
 24→  value: string;
 25→  onChange: (value: string) => void;
 26→  placeholder?: string;
 27→}
 28→
 29→export function SearchDropdown({
 30→  sections,
 31→  value,
 32→  onChange,
 33→  placeholder = 'All',
 34→}: SearchDropdownProps) {
 35→  const [open, setOpen] = useState(false);
 36→  const [activeIndex, setActiveIndex] = useState(0);
 37→  const triggerRef = useRef<HTMLButtonElement>(null);
 38→  const dropdownRef = useRef<HTMLDivElement>(null);
 39→
 40→  const nonEmptySections = useMemo(
 41→    () => sections.filter(s => s.options.length > 0),
 42→    [sections],
 43→  );
 44→
 45→  const flatOptions = useMemo(
 46→    () => nonEmptySections.flatMap(s => s.options),
 47→    [nonEmptySections],
 48→  );
 49→
 50→  const sectionOffsets = useMemo(() => {
 51→    const offsets: number[] = [];
 52→    let total = 0;
 53→    for (const section of nonEmptySections) {
 54→      offsets.push(total);
 55→      total += section.options.length;
 56→    }
 57→    return offsets;
 58→  }, [nonEmptySections]);
 59→
 60→  const selectedOption = flatOptions.find(o => o.value === value);
 61→  const selectedLabel = selectedOption?.label ?? placeholder;
 62→
 63→  const toggle = useCallback(() => {
 64→    setOpen(prev => !prev);
 65→  }, []);
 66→
 67→  useEffect(() => {
 68→    if (!open) return;
 69→    const currentIdx = flatOptions.findIndex(o => o.value === value);
 70→    setActiveIndex(currentIdx >= 0 ? currentIdx : 0);
 71→    dropdownRef.current?.focus();
 72→  }, [
 73→    open,
 74→    flatOptions,
 75→    value,
 76→  ]);
 77→
 78→  const selectOption = useCallback(
 79→    (index: number) => {
 80→      const option = flatOptions[index];
 81→      if (!option) return;
 82→      onChange(option.value);
 83→      setOpen(false);
 84→      triggerRef.current?.focus();
 85→    },
 86→    [
 87→      flatOptions,
 88→      onChange,
 89→    ],
 90→  );
 91→
 92→  useEffect(() => {
 93→    if (!open) return;
 94→
 95→    function handleKeyDown(e: KeyboardEvent) {
 96→      if (e.key === 'Escape') {
 97→        e.preventDefault();
 98→        e.stopPropagation();
 99→        setOpen(false);
100→        triggerRef.current?.focus();
101→        return;
102→      }
103→
104→      if (e.key === 'ArrowDown') {
105→        e.preventDefault();
106→        e.stopPropagation();
107→        setActiveIndex(i => (i < flatOptions.length - 1 ? i + 1 : 0));
108→        return;
109→      }
110→
111→      if (e.key === 'ArrowUp') {
112→        e.preventDefault();
113→        e.stopPropagation();
114→        setActiveIndex(i => (i > 0 ? i - 1 : flatOptions.length - 1));
115→        return;
116→      }
117→
118→      if (e.key === 'Enter') {
119→        e.preventDefault();
120→        e.stopPropagation();
121→        selectOption(activeIndex);
122→      }
123→    }
124→
125→    window.addEventListener('keydown', handleKeyDown, true);
126→    return () => window.removeEventListener('keydown', handleKeyDown, true);
127→  }, [
128→    open,
129→    activeIndex,
130→    flatOptions,
131→    selectOption,
132→  ]);
133→
134→  useEffect(() => {
135→    if (!open) return;
136→
137→    function handleClickOutside(e: MouseEvent) {
138→      const target = e.target as Node;
139→      if (
140→        dropdownRef.current &&
141→        !dropdownRef.current.contains(target) &&
142→        triggerRef.current &&
143→        !triggerRef.current.contains(target)
144→      ) {
145→        setOpen(false);
146→      }
147→    }
148→
149→    document.addEventListener('mousedown', handleClickOutside);
150→    return () => document.removeEventListener('mousedown', handleClickOutside);
151→  }, [open]);
152→
153→  useEffect(() => {
154→    if (!open || !dropdownRef.current) return;
155→    const el = dropdownRef.current.querySelector<HTMLElement>(
156→      `[data-search-dropdown-index="${activeIndex}"]`,
157→    );
158→    el?.scrollIntoView({ block: 'nearest' });
159→  }, [
160→    open,
161→    activeIndex,
162→  ]);
163→
164→  if (flatOptions.length === 0) return null;
165→
166→  return (
167→    <div className="search-dropdown">
168→      <button
169→        ref={triggerRef}
170→        className="search-dropdown__trigger"
171→        type="button"
172→        onClick={toggle}
173→        aria-haspopup="listbox"
174→        aria-expanded={open}
175→      >
176→        <span className="search-dropdown__trigger-label">{selectedLabel}</span>
177→        <svg
178→          className={`search-dropdown__trigger-chevron${open ? ' search-dropdown__trigger-chevron--open' : ''}`}
179→          width="10"
180→          height="10"
181→          viewBox="0 0 10 10"
182→          fill="none"
183→        >
184→          <path
185→            d="M2.5 3.75L5 6.25L7.5 3.75"
186→            stroke="currentColor"
187→            strokeWidth="1.2"
188→            strokeLinecap="round"
189→            strokeLinejoin="round"
190→          />
191→        </svg>
192→      </button>
193→      {open && (
194→        <div
195→          ref={dropdownRef}
196→          className="search-dropdown__menu"
197→          role="listbox"
198→          aria-activedescendant={`search-dropdown-option-${activeIndex}`}
199→          aria-label="Filter options"
200→          tabIndex={-1}
201→        >
202→          <div className="search-dropdown__menu-content">
203→            {nonEmptySections.map((section, sectionIndex) => {
204→              const offset = sectionOffsets[sectionIndex]!;
205→              const titleId = section.title
206→                ? `search-dropdown-section-${sectionIndex}`
207→                : undefined;
208→
209→              return (
210→                <div key={sectionIndex}>
211→                  {sectionIndex > 0 && (
212→                    <div
213→                      className="search-dropdown__separator"
214→                      role="separator"
215→                    />
216→                  )}
217→                  <div role="group" aria-labelledby={titleId}>
218→                    {titleId && (
219→                      <div
220→                        id={titleId}
221→                        className="search-dropdown__section-title"
222→                        role="presentation"
223→                      >
224→                        {section.title}
225→                      </div>
226→                    )}
227→                    {section.options.map((option, optionIndex) => {
228→                      const idx = offset + optionIndex;
229→                      const isActive = idx === activeIndex;
230→                      const isSelected = option.value === value;
231→                      return (
232→                        <button
233→                          key={option.value}
234→                          id={`search-dropdown-option-${idx}`}
235→                          className={`search-dropdown__option${isActive ? ' search-dropdown__option--active' : ''}`}
236→                          data-search-dropdown-index={idx}
237→                          role="option"
238→                          type="button"
239→                          aria-selected={isSelected}
240→                          onClick={() => selectOption(idx)}
241→                          onMouseEnter={() => setActiveIndex(idx)}
242→                        >
243→                          {option.icon && (
244→                            <span className="search-dropdown__option-icon">
245→                              {option.icon}
246→                            </span>
247→                          )}
248→                          <span className="search-dropdown__option-label">
249→                            {option.label}
250→                          </span>
251→                          {isSelected && (
252→                            <svg
253→                              className="search-dropdown__check"
254→                              width="12"
255→                              height="12"
256→                              viewBox="0 0 12 12"
257→                              fill="none"
258→                            >
259→                              <path
260→                                d="M2.5 6L5 8.5L9.5 3.5"
261→                                stroke="currentColor"
262→                                strokeWidth="1.5"
263→                                strokeLinecap="round"
264→                                strokeLinejoin="round"
265→                              />
266→                            </svg>
267→                          )}
268→                        </button>
269→                      );
270→                    })}
271→                  </div>
272→                </div>
273→              );
274→            })}
275→          </div>
276→        </div>
277→      )}
278→    </div>
279→  );
280→}
