 36→
 37→type NavViewData =
 38→  | { type: 'grid' }
 39→  | { type: 'form' }
 40→  | {
 41→      type: 'detail';
 42→      item: ListItemData;
 43→    };
 44→
 45→function filterSections(sections: SectionData[], query: string): SectionData[] {
 46→  if (!query) return sections;
 47→  const lower = query.toLowerCase();
 48→  return sections
 49→    .map(section => ({
 50→      ...section,
 51→      items: section.items.filter(
 52→        item =>
 53→          item.title.toLowerCase().includes(lower) ||
 54→          item.subtitle?.toLowerCase().includes(lower),
 55→      ),
 56→    }))
 57→    .filter(section => section.items.length > 0);
 58→}
 59→
 60→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 61→  if (!query) return colors;
 62→  const lower = query.toLowerCase();
 63→  return colors.filter(
 64→    c =>
 65→      c.title.toLowerCase().includes(lower) ||
 66→      c.subtitle?.toLowerCase().includes(lower),
 67→  );
 68→}
 69→
 70→function flattenItems(sections: SectionData[]): ListItemData[] {
 71→  return sections.flatMap(s => s.items);
 72→}
 73→
 74→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 75→  switch (entry.type) {
 76→    case 'label':
 77→      return (
 78→        <DetailMetadata.Label
 79→          key={index}
 80→          title={entry.title}
 81→          text={entry.text}
 82→        />
 83→      );
 84→    case 'link':
 85→      return (
 86→        <DetailMetadata.Link
 87→          key={index}
 88→          title={entry.title}
 89→          text={entry.text}
 90→          target={entry.target}
 91→        />
 92→      );
 93→    case 'tag-list':
 94→      return (
 95→        <DetailMetadata.TagList key={index} title={entry.title}>
 96→          {entry.tags.map(tag => (
 97→            <DetailMetadata.Tag
 98→              key={tag.text}
 99→              text={tag.text}
100→              color={tag.color}
101→            />
102→          ))}
103→        </DetailMetadata.TagList>
104→      );
105→    case 'separator':
106→      return <DetailMetadata.Separator key={index} />;
107→  }
108→}
109→
110→function ColorSwatch({ color }: { color: string }) {
111→  return (
112→    <div
113→      className="grid-item__color-swatch"
114→      style={{ backgroundColor: color }}
115→    />
116→  );
