142→interface SnippetFormState {
143→  name: string;
144→  keyword: string;
145→  snippet: string;
146→  category: string;
147→  isShared: boolean;
148→  expiresAt: string;
149→}
150→
151→const INITIAL_SNIPPET_FORM: SnippetFormState = {
152→  name: '',
153→  keyword: '',
154→  snippet: '',
155→  category: 'general',
156→  isShared: false,
157→  expiresAt: '',
158→};
159→
160→const SNIPPET_CATEGORIES = [
161→  {
162→    label: 'General',
163→    value: 'general',
164→  },
165→  {
166→    label: 'Code',
167→    value: 'code',
168→  },
169→  {
170→    label: 'Email',
171→    value: 'email',
172→  },
173→  {
174→    label: 'Template',
175→    value: 'template',
176→  },
177→];
178→
179→interface CreateSnippetViewProps {
180→  onSubmit: (form: SnippetFormState) => void;
181→}
182→
183→function CreateSnippetView({ onSubmit }: CreateSnippetViewProps) {
184→  const [snippetForm, setSnippetForm] =
185→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
186→  const [formErrors, setFormErrors] = useState<
187→    Partial<Record<keyof SnippetFormState, string>>
188→  >({});
189→
190→  const handleSubmit = useCallback(() => {
191→    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
192→    if (!snippetForm.name.trim()) {
193→      errors.name = 'Name is required';
194→    }
